def calculate_atr(high, low, close, period=14):
    """
    Calculate the Average True Range (ATR) using High, Low, and Close prices.

    Parameters:
    high (list): List of high prices
    low (list): List of low prices
    close (list): List of close prices
    period (int): Period for ATR calculation (default: 14)

    Returns:
    list: List of ATR values
    """
    tr = []
    atr = []

    for i in range(len(high)):
        if i == 0:
            tr.append(high[i] - low[i])
        else:
            tr.append(max(high[i] - low[i], abs(high[i] - close[i-1]), abs(low[i] - close[i-1])))

    for i in range(len(tr)):
        if i < period - 1:
            atr.append(0)
        elif i == period - 1:
            atr.append(sum(tr[:period]) / period)
        else:
            atr.append((atr[i-1] * (period - 1) + tr[i]) / period)

    return atr
